import React from 'react';
import ReactDOM from 'react-dom/client';
// Make sure App.tsx or App.jsx exists in the same folder.
// If the file is missing, create 'App.tsx' with a basic component:
import App from './App';

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
